import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/launcher-screen.B4Y3DSWp.js";import{t as o}from"./chunks/macos-downloads.DCRwPSpe.js";const s=JSON.parse(`{"title":"Installation von Fabric","description":"Eine Schritt-für-Schritt-Anleitung zur Installation von Fabric.","frontmatter":{"title":"Installation von Fabric","description":"Eine Schritt-für-Schritt-Anleitung zur Installation von Fabric.","authors":["IMB11","Benonardo","modmuss50"],"files":[]},"headers":[],"relativePath":"de_de/1.21.1/players/installing-fabric.md","filePath":"versions/1.21.1/translated/de_de/players/installing-fabric.md","lastUpdated":1761424914000}`);var c={name:`de_de/1.21.1/players/installing-fabric.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Installation von Fabric <a class="header-anchor" href="#h1" aria-label="Permalink to “Installation von Fabric”">​</a></h1><p>Dieser Leitfaden bezieht sich ausschließlich auf den offiziellen Minecraft Launcher. Für die Launcher von Drittanbietern solltest du deren Dokumentation verwenden.</p><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Herunterladen des Fabric-Installers <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Herunterladen des Fabric-Installers”">​</a></h2><p>Der Fabric-Installer kann von der <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">Fabric-Webseite</a> heruntergeladen werden.</p><p>Wenn du Windows verwendest, lade die <code>.exe</code>-Version (<code>Download For Windows</code>) herunter, da sie keine Java-Installation auf dem System benötigt. Stattdessen wird die Java-Installation des offiziellen Launchers verwendet.</p><p>Für macOS und Linux solltest du die <code>.jar</code>-Version verwenden. Manchmal musst du Java vor diesem Schritt installieren.</p><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Ausführen des Fabric-Installers <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Ausführen des Fabric-Installers”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Schließe vor dem Ausführen des Installers zuerst Minecraft und den Minecraft Launcher.</p></div><details class="details custom-block"><summary>Informationen für macOS-Nutzer</summary><p>Auf macOS musst du möglicherweise zuerst einen Rechtsklick auf die <code>.jar</code>-Datei im Downloads-Verzeichnis machen, und <code>Öffnen</code> zum Ausführen klicken.</p><p><img src="/assets/players/installing-fabric/macos-downloads.png" alt="MacOS Kontextmenü im Fabric-Installer" loading="lazy"></p><p>Bei der Frage &quot;Möchten Sie es wirklich öffnen?&quot;, klicke erneut auf <code>Öffnen</code>.</p></details><p>Wenn du den Installer geöffnet hast, sollte diese Oberfläche erscheinen:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Fabric-Installer mit &quot;Installieren&quot; hervorgehoben" loading="lazy"></p><p>Um Fabric zu installieren, wähle einfach die Spielversion aus der Liste und klicke <code>Installieren</code>.</p><div class="warning custom-block"><p class="custom-block-title">WICHTIG</p><p>Stelle sicher, dass die Option &#39;Profil erstellen&#39; aktiviert ist.</p></div><h2 id="3-you-re-done" tabindex="-1">3. Du hast es geschafft! <a class="header-anchor" href="#3-you-re-done" aria-label="Permalink to “3. Du hast es geschafft!”">​</a></h2><p>Sobald das Installationsprogramm fertig ist, kannst du den Minecraft-Launcher öffnen und das Fabric-Profil aus der Liste in der unteren linken Ecke auswählen und spielen!</p><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="Minecraft-Launcher mit ausgewähltem Fabric-Profil" loading="lazy"></p><p>Jetzt, nachdem du Fabric installiert hast, kannst du dem Spiel Mods hinzufügen! Weitere Informationen zum Finden von Mods findest du in dem Leitfaden <a href="./finding-mods">Vertrauenswürdige Mods finden</a>.</p><p>Fall dir beim Folgen dieser Anleitungen irgendwelche Fehler auftreten, kannst du nach Hilfe im <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric-Discord</a> im Kanal <code>#player-support</code> fragen.</p>`,18)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};